        # Cohen's d
        d = abs(np.mean(pos[:, top_n]) - np.mean(neg[:, top_n])) / \
            (np.sqrt((np.var(pos[:, top_n]) + np.var(neg[:, top_n])) / 2) + 1e-10)
        # Accuracy
